parameters.query:
=SELECT *
FROM public.pending_orders
WHERE chat_id = {{ $('Start').first().json.tool_input.chat_id }}
AND status = 'awaiting_confirmation'
ORDER BY COALESCE(updated_at, created_at) DESC
LIMIT 1;

parameters.jsCode:
const chatId = $('Start').first().json.tool_input.chat_id;
const rows = $input
  .all()
  .map((entry) => entry.json)
  .filter((entry) => entry && entry.order_id);

if (rows.length === 0) {
  return [
    {
      json: {
        error: true,
        chat_id: chatId,
        pending_order_id: null,
        confirmation_message: 'There is no pending order to confirm. Please add items and checkout first.',
      },
    },
  ];
}

rows.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
const pending = rows[0];

if (new Date(pending.expires_at) < new Date()) {
  return [
    {
      json: {
        error: true,
        chat_id: chatId,
        pending_order_id: pending.order_id,
        confirmation_message: 'Your bill has expired (bills are valid for 30 minutes). Please type checkout to get a fresh bill.',
      },
    },
  ];
}

let orderDetails;
try {
  orderDetails = typeof pending.order_details_json === 'string'
    ? JSON.parse(pending.order_details_json)
    : pending.order_details_json;
} catch (err) {
  return [
    {
      json: {
        error: true,
        chat_id: chatId,
        pending_order_id: pending.order_id,
        confirmation_message: 'Could not read order details. Please try checkout again.',
      },
    },
  ];
}

const payload = {
  error: false,
  pending_order_id: pending.order_id,
  chat_id: chatId,
  order_details: orderDetails,
};

return [
  {
    json: payload,
  },
];

const d = $('Parse Pending Order').first().json;

if (d.error) {
  return [
    {
      json: d,
    },
  ];
}

const orderDetails = d.order_details || {};
const items = Array.isArray(orderDetails.items_in_final_order)
  ? orderDetails.items_in_final_order
  : [];

if (items.length === 0) {
  return [
    {
      json: {
        error: true,
        chat_id: d.chat_id,
        confirmation_message: 'This pending order has no items. Please type checkout to regenerate your bill.',
      },
    },
  ];
}

const safeSql = (value) => String(value ?? '').replace(/'/g, "''");
const appliedPromoCodes = (orderDetails.applied_promos || []).map((promo) => promo.code).join(', ');

const payload = {
  error: false,
  order_id: orderDetails.order_id,
  chat_id: orderDetails.chat_id,
  store_id: orderDetails.store_id || 1,
  shipping_address: orderDetails.address || '',
  shipping_address_sql: safeSql(orderDetails.address || ''),
  subtotal_before_discounts: Number(orderDetails.subtotal_before_discounts || 0),
  total_discount_applied: Number(orderDetails.total_discount_applied || 0),
  final_order_total: Number(orderDetails.final_order_total || 0),
  applied_order_level_promo_ids: appliedPromoCodes,
  applied_order_level_promo_ids_sql: safeSql(appliedPromoCodes),
  cart_id: orderDetails.cart_id,
  items,
  pending_order_id: d.pending_order_id,
  order_details_json_safe: safeSql(JSON.stringify(orderDetails)),
};

return [
  {
    json: payload,
  },
];

const summary = $('Prepare Order Summary').first().json || {};
const root = (() => {
  try {
    const start = $('Start').first();
    if (start && start.json) return start.json;
  } catch {}
  if ($json && typeof $json === 'object' && Object.keys($json).length > 0) return $json;
  try {
    const current = $input.first();
    return (current && current.json) ? current.json : {};
  } catch {}
  return {};
})();
const toolInput = (root.tool_input && typeof root.tool_input === 'object') ? root.tool_input : root;

const items = Array.isArray(summary.items) ? summary.items : [];
const lines = [];
for (const item of items) {
  const unit = item && item.unit ? ' ' + item.unit : '';
  const name = item && (item.original_name || item.name) ? (item.original_name || item.name) : 'item';
  const qty = item && item.quantity !== undefined ? item.quantity : 0;
  lines.push('• ' + name + ' × ' + qty + unit);
}
if (lines.length === 0) {
  lines.push('• Items unavailable');
}

const total = Number(summary.final_order_total || 0).toFixed(2);
const orderId = String(summary.order_id || '');
const chatId = String(summary.chat_id || '');
const shippingAddress = String(summary.shipping_address || '');
const enablePricing = (() => {
  try { return $('Get Pricing Flag').first().json.enable_pricing !== false; } catch { return true; }
})();

const totalLine = enablePricing ? 'Total: ₹' + total + '\n\n' : '';
const customerMsg =
  'Order confirmed\n\n' +
  'Order ID: ' + orderId + '\n' +
  'Deliver to: ' + shippingAddress + '\n' +
  totalLine +
  lines.join('\n') + '\n\n' +
  'The store has your order now. You can track it any time.';

const ownerTotalLine = enablePricing ? 'Total: Rs.' + total + '\n' : '';
const ownerMsg =
  'New Order Received!\n\n' +
  'Order ID: ' + orderId + '\n' +
  'Customer: ' + chatId + '\n' +
  ownerTotalLine +
  'Deliver to: ' + shippingAddress + '\n\n' +
  'Items:\n' + lines.join('\n') + '\n\n' +
  'Reply with:\n' +
  'ACCEPT ' + orderId + '\n' +
  'REJECT ' + orderId;

return [{ json: {
  confirmation_message: customerMsg,
  chat_id: chatId,
  customer_ui_state: 'ORDER_CONFIRMED',
  message_type: 'button',
  buttons: [
    { id: 'track_order', title: 'Track Order' },
    { id: 'new_order', title: 'Shop Again' },
  ],
  owner_msg: ownerMsg,
  order_id: orderId,
  store_id: Number(summary.store_id || 1),
  test_mode: toolInput.test_mode === true,
} }];

